SELECT PRD_SN
FROM PRODUCT
WHERE PRD_SN = #{productId}
  AND USR_SN = #{sellerUserId}
FOR UPDATE

SELECT PRD_TRD_METHOD_CD
FROM PRODUCT
WHERE PRD_SN = #{productId}

mapper.insert:
INSERT INTO TRADE_STATUS_HIST (
    TRD_SN,
    TRD_STS_HST_STATUS_CD,
    TRD_STS_HST_RSN_CN
)
VALUES (
    #{tradeId},
    #{statusCode},
    #{reason}
)

mapper.select:
SELECT t.TRD_SN AS tradeId, CASE WHEN t.BYPR_USR_SN = #{userId} THEN 'BUYER' ELSE 'SELLER' END AS userRole, p.PRD_NM AS productName, CASE WHEN t.BYPR_USR_SN = #{userId} THEN t.SLLR_USR_SN ELSE t.BYPR_USR_SN END AS counterpartUserId, CASE WHEN t.BYPR_USR_SN = #{userId} THEN seller.USR_NM ELSE buyer.USR_NM END AS counterpartNickname, t.TRD_AMT AS tradeAmount, t.TRD_REG_DT AS createdAt, t.TRD_STATUS_CD AS tradeStatus, CASE p.PRD_TRD_METHOD_CD WHEN 'TRDC0009' THEN 'DELIVERY' WHEN 'TRDC0010' THEN 'OFFLINE' END AS tradeMethod FROM TRADE t JOIN PRODUCT p ON p.PRD_SN = t.PRD_SN JOIN USERS seller ON seller.USR_SN = t.SLLR_USR_SN JOIN USERS buyer ON buyer.USR_SN = t.BYPR_USR_SN WHERE t.TRD_TYPE_CD = 'TRDC0001' AND (t.SLLR_USR_SN = #{userId} OR t.BYPR_USR_SN = #{userId})
AND t.BYPR_USR_SN = #{userId}
AND t.SLLR_USR_SN = #{userId}
AND t.TRD_STATUS_CD = #{statusCode}
AND ( LOWER(p.PRD_NM) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER( CASE WHEN t.BYPR_USR_SN = #{userId} THEN seller.USR_NM ELSE buyer.USR_NM END ) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR CAST(t.TRD_SN AS CHAR) LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY t.TRD_REG_DT DESC, t.TRD_SN DESC

SELECT t.PRD_SN AS prdSn, t.TRD_SN AS tradeSn, t.TRD_STATUS_CD AS tradeStatusCd FROM TRADE t WHERE t.TRD_TYPE_CD = 'TRDC0001' AND t.PRD_SN IN
#{prdSn}
ORDER BY t.PRD_SN, t.TRD_REG_DT DESC, t.TRD_SN DESC

