mapper.update:
UPDATE TRADE
SET TRD_STATUS_CD = 'TRDC0004',
    TRD_UPDT_ID = #{updaterId}
WHERE TRD_SN = #{tradeId}
  AND TRD_STATUS_CD = 'TRDC0003'

UPDATE TRADE
SET TRD_STATUS_CD = 'TRDC0005',
    TRD_AUTO_CMPL_DT = #{autoCompleteAt},
    TRD_UPDT_ID = #{updaterId}
WHERE TRD_SN = #{tradeId}

UPDATE TRADE
SET TRD_STATUS_CD = 'TRDC0006',
    TRD_UPDT_ID = #{updaterId}
WHERE TRD_SN = #{tradeId}
  AND TRD_STATUS_CD = 'TRDC0005'
  AND TRD_AUTO_CMPL_DT <= #{now}

UPDATE TRADE
SET TRD_STATUS_CD = 'TRDC0008',
    TRD_UPDT_ID = #{updaterId}
WHERE TRD_SN = #{tradeId}
  AND TRD_TYPE_CD = 'TRDC0001'
  AND TRD_STATUS_CD IN ('TRDC0003', 'TRDC0004', 'TRDC0005')
